import InlineStack from "~/components/molecules/InlineStack";
import Description from "~/components/molecules/Description";
import BlockStack from "~/components/molecules/BlockStack";
import { __ } from "@wordpress/i18n";
import Button from "~/components/atoms/Button";
import Card from "~/components/molecules/Card";
import Text from "~/components/atoms/Text";
import clsx from "clsx";
import {
    SettingsFieldProps,
    SettingsSubFieldProps,
} from "./SettingsField.type";

const SettingsField: SettingsFieldProps = ({
    id,
    style,
    className,
    title,
    description,
    docLink,
    background = "white",
    border = "primary-light",
    borderStyle = "solid",
    rounded,
    gap = 20,
    children,
    isIgnoreChildren = false,
    action,
    secondaryAction,
    statusProps,
}) => {
    return (
        <Card
            id={id}
            style={style}
            background={background}
            border={border}
            borderStyle={borderStyle}
            rounded={rounded}
            statusProps={statusProps}
            className={className}
        >
            <InlineStack
                align="between"
                gap={10}
                style={{
                    marginBottom:
                        children &&
                        !isIgnoreChildren &&
                        (title || description || action || secondaryAction)
                            ? 16
                            : 0,
                }}
            >
                <BlockStack gap={10}>
                    <InlineStack gap={15}>
                        {action && action}

                        {title && (
                            <Text as="h4" weight="medium">
                                {title}
                            </Text>
                        )}

                        {secondaryAction && secondaryAction}
                    </InlineStack>

                    {description && <Description text={description} />}
                </BlockStack>

                {docLink && (
                    <Button
                        variant="outlined"
                        size="small"
                        startIcon="info"
                        href={docLink}
                        target="_blank"
                    >
                        {__("Documentation", "ninja-drive")}
                    </Button>
                )}
            </InlineStack>

            <BlockStack gap={gap}>{children}</BlockStack>
        </Card>
    );
};

const SettingsSubField: React.FC<SettingsSubFieldProps> = ({
    id,
    style,
    className,
    title,
    description,
    docLink,
    background = "primary-extralight",
    border,
    borderStyle = "dashed",
    rounded = "md",
    gap = 20,
    children,
    action,
    secondaryAction,
    isIgnoreChildren,
    depend,
    dependOn = "",
    statusProps,
}) => {
    const classes = clsx(className, depend && "pn-settings-field-disabled");

    const handleClick = (e: React.MouseEvent) => {
        const dependent = document.getElementById(dependOn);

        if (dependent && depend) {
            e.stopPropagation();

            const label = dependent.parentElement as HTMLElement;

            if (!label) return;

            label.classList.add("pn-blink");

            setTimeout(() => {
                label.classList.remove("pn-blink");
            }, 500);
        }
    };

    return (
        <Card
            id={id}
            style={style}
            background={background}
            border={border}
            borderStyle={borderStyle}
            rounded={rounded}
            statusProps={statusProps}
            className={classes}
            onClick={handleClick}
        >
            <InlineStack
                align="between"
                gap={10}
                style={{
                    marginBottom:
                        children &&
                        !isIgnoreChildren &&
                        (title || description || action || secondaryAction)
                            ? 16
                            : 0,
                }}
            >
                <BlockStack gap={10}>
                    <InlineStack gap={15}>
                        {action && action}

                        {title && (
                            <Text as="h4" weight="medium">
                                {title}
                            </Text>
                        )}

                        {secondaryAction && secondaryAction}
                    </InlineStack>

                    {description && <Description text={description} />}
                </BlockStack>

                {docLink && (
                    <Button
                        variant="outlined"
                        size="small"
                        startIcon="info"
                        href={docLink}
                        target="_blank"
                    >
                        {__("Documentation", "ninja-drive")}
                    </Button>
                )}
            </InlineStack>

            <BlockStack gap={gap}>{children}</BlockStack>
        </Card>
    );
};

SettingsField.SubField = SettingsSubField;

export default SettingsField;
